begin;alter table public.commercial_simulations add column if not exists scenario_type text not null default'rule_default'check(scenario_type in('rule_default','higher_down_payment','shorter_term')),add column if not exists requested_down_percent numeric(5,2),add column if not exists requested_installments integer,add column if not exists calculation_version integer not null default 1,add column if not exists assumptions text[]not null default'{}',add column if not exists requires_human_approval boolean not null default true,add column if not exists confirmed_as_proposal boolean not null default false;create table if not exists public.commercial_simulation_events(id uuid primary key default gen_random_uuid(),organization_id uuid not null references public.organizations(id)on delete cascade,lead_id uuid not null references public.leads(id)on delete cascade,simulation_id uuid not null references public.commercial_simulations(id)on delete cascade,actor_id uuid not null references public.profiles(id),event_type text not null check(event_type in('created','review_requested','invalidated','expired')),scenario_type text not null,release_version integer not null,rule_version integer not null,created_at timestamptz not null default now());alter table public.commercial_simulation_events enable row level security;create policy commercial_simulation_events_scope on public.commercial_simulation_events for select to authenticated using(organization_id=(select public.current_organization_id())and(select private.can_view_lead(lead_id)));revoke all on public.commercial_simulation_events from anon;revoke insert,update,delete on public.commercial_simulation_events from authenticated;grant select on public.commercial_simulation_events to authenticated;grant all on public.commercial_simulation_events to service_role;commit;
